<template><div class="document-page" v-loading="loading"><div class="document-header"><div><el-button link @click="router.push(basePath)"><el-icon><ArrowLeft/></el-icon> 返回</el-button><h1>{{isOut?'借出':'借入'}}详情</h1></div><div><el-button v-if="detail?.status==='DRAFT'" type="success" @click="approve">审核生效</el-button><el-button v-if="detail&&['APPROVED','PARTIALLY_RETURNED'].includes(detail.status)" type="primary" @click="openReturn">办理归还</el-button><el-button v-if="detail?.status==='DRAFT'" type="danger" plain @click="cancel">取消单据</el-button></div></div><el-card><template #header><div class="section-title"><span>借用信息</span><div><el-tag :type="statusType(detail?.status)">{{statusLabel(detail?.status)}}</el-tag><el-tag v-if="detail?.overdue" type="danger" class="overdue-tag">逾期</el-tag></div></div></template><el-descriptions v-if="detail" :column="3" border><el-descriptions-item label="单号">{{detail.borrowNo}}</el-descriptions-item><el-descriptions-item label="仓库">{{detail.warehouseName}}</el-descriptions-item><el-descriptions-item label="往来单位">{{detail.partnerName}}</el-descriptions-item><el-descriptions-item label="借用日期">{{detail.borrowDate}}</el-descriptions-item><el-descriptions-item label="预计归还">{{detail.expectedReturnDate||'-'}}</el-descriptions-item><el-descriptions-item label="总数量">{{detail.totalQuantity}}</el-descriptions-item><el-descriptions-item label="已归还">{{detail.returnedQuantity}}</el-descriptions-item><el-descriptions-item label="未归还">{{detail.remainingQuantity}}</el-descriptions-item><el-descriptions-item label="备注">{{detail.remark||'-'}}</el-descriptions-item></el-descriptions></el-card><el-card class="section-card"><template #header><div class="section-title"><span>借用明细</span><small>共 {{detail?.items?.length||0}} 项商品</small></div></template><el-table :data="detail?.items||[]" border stripe><el-table-column type="index" label="序号" width="60"/><el-table-column prop="productCode" label="商品编码" width="135"/><el-table-column prop="productName" label="商品名称" min-width="180"/><el-table-column prop="unitName" label="单位" width="75"/><el-table-column prop="quantity" label="借用数量" width="105" align="right"/><el-table-column prop="returnedQuantity" label="已归还" width="100" align="right"/><el-table-column prop="remainingQuantity" label="未归还" width="100" align="right"/><el-table-column prop="unitCost" label="单位成本" width="110" align="right"/><el-table-column prop="remark" label="备注" min-width="140"/></el-table></el-card><el-dialog title="办理归还" v-model="returnVisible" width="760px"><el-alert :title="isOut?'借出归还会增加本仓库存。':'借入归还会减少本仓库存，请确保库存充足。'" type="warning" show-icon :closable="false" class="return-alert"/><el-form label-width="90px"><el-form-item label="归还日期"><el-date-picker v-model="returnForm.returnDate" type="date" value-format="YYYY-MM-DD"/></el-form-item></el-form><el-table :data="returnForm.items" border><el-table-column prop="productName" label="商品" min-width="180"/><el-table-column prop="remainingQuantity" label="未归还" width="110"/><el-table-column label="本次归还" width="190"><template #default="{row}"><el-input-number v-model="row.returnQuantity" :min="0" :max="Number(row.remainingQuantity)" :precision="4" style="width:155px"/></template></el-table-column></el-table><template #footer><el-button @click="returnVisible=false">取消</el-button><el-button type="primary" :loading="returning" @click="submitReturn">确认归还</el-button></template></el-dialog></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{approveInventoryBorrow,cancelInventoryBorrow,getInventoryBorrow,returnInventoryBorrow}from'@/api/inventory';const route=useRoute(),router=useRouter(),id=Number(route.params.id),type=computed(()=>String(route.meta.borrowType||'BORROW_OUT')),isOut=computed(()=>type.value==='BORROW_OUT'),basePath=computed(()=>isOut.value?'/inventory/borrow-outs':'/inventory/borrow-ins'),loading=ref(false),detail=ref<any>(null),returnVisible=ref(false),returning=ref(false),returnForm=reactive<any>({returnDate:new Date().toISOString().slice(0,10),items:[]});onMounted(async()=>{await load();if(route.query.return==='1'&&['APPROVED','PARTIALLY_RETURNED'].includes(detail.value?.status))openReturn()});async function load(){loading.value=true;try{detail.value=(await getInventoryBorrow(id)).data}finally{loading.value=false}}function statusLabel(v:string){return({DRAFT:'草稿',APPROVED:'借用中',PARTIALLY_RETURNED:'部分归还',COMPLETED:'已归还',CANCELLED:'已取消'}as any)[v]||v}function statusType(v:string){return({DRAFT:'info',APPROVED:'warning',PARTIALLY_RETURNED:'primary',COMPLETED:'success',CANCELLED:'danger'}as any)[v]||''}async function approve(){await ElMessageBox.confirm(`审核后将${isOut.value?'减少':'增加'}仓库库存，是否继续？`,'审核借用单',{type:'warning'});await approveInventoryBorrow(id);ElMessage.success('借用单已生效');load()}function openReturn(){returnForm.returnDate=new Date().toISOString().slice(0,10);returnForm.items=(detail.value.items||[]).filter((i:any)=>Number(i.remainingQuantity)>0).map((i:any)=>({itemId:i.id,productName:i.productName,remainingQuantity:i.remainingQuantity,returnQuantity:0}));returnVisible.value=true}async function submitReturn(){const items=returnForm.items.filter((i:any)=>Number(i.returnQuantity)>0).map((i:any)=>({itemId:i.itemId,quantity:i.returnQuantity}));if(!returnForm.returnDate)return ElMessage.warning('请选择归还日期');if(!items.length)return ElMessage.warning('请至少填写一项归还数量');returning.value=true;try{await returnInventoryBorrow(id,{returnDate:returnForm.returnDate,items});ElMessage.success('归还成功');returnVisible.value=false;load()}finally{returning.value=false}}async function cancel(){await ElMessageBox.confirm('确定取消该借用单吗？','取消借用单',{type:'warning'});await cancelInventoryBorrow(id);ElMessage.success('借用单已取消');load()}</script>
<style scoped>.document-page{padding-bottom:24px}.document-header{min-height:66px;display:flex;align-items:center;justify-content:space-between;margin:-16px -20px 16px;padding:0 22px;background:#fff;border-bottom:1px solid #edf0f5}.document-header>div,.section-title{display:flex;align-items:center;gap:10px}.document-header h1{margin:0;font-size:19px}.section-card{margin-top:14px}.section-title{justify-content:space-between}.section-title span{font-size:16px;font-weight:600}.section-title small{color:#a1a8b3}.overdue-tag{margin-left:6px}.return-alert{margin-bottom:14px}</style>
